var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"하아… 요즘 화가 나서 잠도 제대로 못 자겠어요.","JPN":"はあ……最近イライラしてちゃんと眠れません。","ENG":"*Sigh* I'm so angry these days that I can't even get a good night's sleep.","TWN":"哈…這幾天氣得我睡不好覺。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"결국 괴도도 못 잡고 이게 뭐예요!","JPN":"結局怪盗も捕まえられなかったし、何なんですか！","ENG":"And in the end, we couldn't even catch those thieves!","TWN":"到最後都沒能抓到怪盜，這算什麼！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그래도 그 부잣집 아가씨가 따로 의뢰비도 챙겨주셨잖아.","JPN":"でも、あのお金持ちのお嬢様が依頼料をくれたじゃないか。","ENG":"But at least our rich client gave us our money.","TWN":"好在那個富家小姐另外支付了酬勞。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"덕분에 우리도 탐정 일을 다시 할 수 있게 됐고.","JPN":"おかげで僕たちもまた探偵の仕事ができるようになったし。","ENG":"Thanks to that, we're still able to work as detectives.","TWN":"多虧於此，我們才能再次進行偵探工作。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"그치만… 이건 이겼다고 할 수 없다구요!","JPN":"でも……これじゃあ勝ったとは言えません！","ENG":"But... we can't say that we won!","TWN":"但…我們根本沒有贏！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"결과만 좋으면 다 좋은 거 아니겠어?","JPN":"結果オーライじゃないか？","ENG":"What matters is that it all ended well, don't you think?","TWN":"結果是好的，那一切都是好的，不是嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"당신은 참 팔자 좋아서 부럽네요.","JPN":"あなたってば、のんきでうらやましいですね。","ENG":"I envy your optimism.","TWN":"你還真是樂觀…"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"점심은 주문했나요? 설마 또 햄버거는 아니겠죠?","JPN":"昼食は注文しましたか？　まさか、またハンバーガーじゃないでしょうね。","ENG":"Did you order lunch yet? It's not hamburgers again, is it?","TWN":"你訂午餐了嗎？不會又是漢堡吧？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"햄버거… 맞는데? 유명한 수제 버거집이래.","JPN":"ハンバーガー……だけど？　有名な手作りバーガー屋さんだってさ。","ENG":"It is... burgers. It's from a famous gourmet place.","TWN":"沒錯…這次是一家很有名氣的手工漢堡店。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그 메이드가 추천해 준 집인데, 인스턴트하곤 비교가 안 될 거라더라.","JPN":"あのメイドにおすすめされたお店なんだけど、チェーン店とは比べ物にならないらしいぞ。","ENG":"It's the one the maid recommended. I'm sure it tastes way better than the microwaved ones.","TWN":"是上次的那個女僕推薦的，說是速食漢堡完全比不了。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"그것도 분명... 괴도한테 받았다는 버거였죠?","JPN":"それって確か……怪盗からもらったバーガーでしたよね？","ENG":"Isn't that the same one... she got from the phantom thief?","TWN":"難道是…怪盜給的那個漢堡？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"이제 그만 좀 화내고 TV나 보면서 기다리자고.","JPN":"そう怒らないで、テレビでも見ながら待とうじゃないか。","ENG":"Stop your fuming and let's wait for the food to arrive while watching TV.","TWN":"別生氣了，一邊等一邊看電視吧。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"저는 지금 이곳, 세계 최대 규모의 만화 행사에 나와 있습니다.","JPN":"私はただいま、世界最大規模のマンガイベントに来ています。","ENG":"I'm here now at the biggest comic event in the world.","TWN":"觀眾朋友們，我現在來到了全球規模最大的動漫節。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"현장에는 수 많은 코스플레이어들의 뜨거운 열기가 느껴지는데요.","JPN":"現場からは数多くのコスプレイヤーたちの熱気が感じられます。","ENG":"The scene is intense with countless enthusiastic cosplayers!","TWN":"在現場，可以感受到無數Coser的熱情。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"앗, 특이한 모습을 하고 있는 분이 계시네요. 한번 모셔보겠습니다!","JPN":"あっ、独特な格好の方がいらっしゃいますね。インタビューしてみましょう！","ENG":"Oh, there's a peculiar one over there! I'll see if I can get an interview!","TWN":"喔，有一個長相奇特的人。讓我們來採訪一下吧！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"성함이 어떻게 되시나요? 네모 씨… 라고 불러드릴까요?","JPN":"お名前は？　四角さん……とお呼びしても？","ENG":"What's your name? May I call you... Mr. Square?","TWN":"你叫什麼名字？方塊先生…我可以這樣稱呼你嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FOOLSDAY_THIEF_GAP_NULL","text":{"KOREA":"한때 졸부란 이름으로 불리던 시절이 있었지. 하지만 지금은 <color=#ffd34c>괴도 갑</color>이라 불러주게.","JPN":"一時成金という名前で呼ばれた時代があった。だが、今は<color=#ffd34c>怪盗-甲-</color>と呼んでくれたまえ。","ENG":"I was once called a parvenu. But now, I go by the name <color=#ffd34c>Phantom Thief G.A.P.</color>","TWN":"曾經有一段時間，我被稱為暴發戶。但現在還是叫我<color=#ffd34c>怪盜甲</color>吧。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_THIEF_GAP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L23_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"괴도 갑? 설마?!","JPN":"怪盗-甲-？　まさか！？","ENG":"Phantom Thief G.A.P.? Then are you?!","TWN":"怪盜甲？難道？！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"네 괴도 갑 씨. 이 복장은 역시 괴도 코스프레인가요?","JPN":"はい、怪盗-甲-さん。この服装は、やはり怪盗のコスプレでしょうか？","ENG":"Yes, Mr. Phantom Thief G.A.P. Are you cosplaying as a phantom thief?","TWN":"好的，怪盜甲先生。這身服裝是在Cosplay怪盜嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FOOLSDAY_THIEF_GAP_NULL","text":{"KOREA":"코스프레라니! 이 몸은 진짜 괴도란 말일세!","JPN":"コスプレとは何だ！　私は本物の怪盗なのだ！","ENG":"Cosplaying?! I am a real phantom thief!","TWN":"什麼Cosplay！我就是真正的怪盜！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_THIEF_GAP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FOOLSDAY_THIEF_GAP_NULL","text":{"KOREA":"도둑질로 삶을 연명하고 있던 난, 결국 괴도 갑으로 각성하게 되었다네.","JPN":"泥棒で生活していた私は、結局怪盗-甲-として覚醒することになった。","ENG":"After years of making ends meet with stealing, I awakened as Phantom Thief G.A.P.","TWN":"一直靠著偷竊苟延殘喘的我，終於覺醒成為了怪盜甲！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_THIEF_GAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_THIEF_GAP_NULL","text":{"KOREA":"마침 생방송이니 예고장 대신 전하지! 이 몸이 지정한 타겟은 그 유명한 명탐정…!","JPN":"ちょうど生配信中だから、予告状の代わりに伝えよう！　今回の私のターゲットは、かの有名な名探偵……！","ENG":"And since I'm on live television, I'd like to send a message here instead of a calling card! The next target of mine is the famous detective–!","TWN":"既然是直播，就不發預告函了！我這次的目標，就是那個大名鼎鼎的偵探…！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_THIEF_GAP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"네~ 네모 씨의 개성 있는 인터뷰 잘 들었습니다.","JPN":"はい～四角さんの個性豊かなインタビュー、ありがとうございました。","ENG":"Okay! Thank you for a fantastic interview, Mr. Square.","TWN":"好的～以上是方塊先生充滿個性的採訪。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FOOLSDAY_THIEF_GAP_NULL","text":{"KOREA":"잘 찍고 있나? 그리고 내 이름은 괴도 갑이다만…?!","JPN":"ちゃんと撮れているのかね？　それに、私の名前は怪盗-甲-なのだが……！？","ENG":"D-did you get all that? And my name is Phantom Thief G.A.P...","TWN":"有沒有好好拍？還有，我叫怪盜甲…？！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"그럼 다음 분 인터뷰 모시겠습니다!","JPN":"では、次の方に伺いましょう！","ENG":"Let's move on to our next interviewee!","TWN":"那麼，我們來採訪下一個人吧！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그럼... 이제 우릴 노리는 괴도가 세 명이라는 건가…?","JPN":"じゃあ……今僕たちを狙ってる怪盗は3人ってことか……？","ENG":"Then... there are now three phantom thieves after us...?","TWN":"就是說…現在有三個怪盜盯上了我們…？"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"겁먹을 필요 없어요 로널드.","JPN":"怖がる必要はありません、ロナルド・リー。","ENG":"There's nothing to fear, Ronald Lee.","TWN":"沒必要害怕，羅那魯多·李。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"설령 괴도가 열 명일지라도 얼마든지 상대해 드리죠.","JPN":"たとえ怪盗が10人だったとしても、いくらでもお相手します。","ENG":"Even if there are ten, I'll take on all of them.","TWN":"就算有十個怪盜，我也毫不畏懼。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그, 그건 내가 사양이라고!","JPN":"そ、それは僕がお断りだよ！","ENG":"C-count me out of that!","TWN":"我、我才不要呢！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"휴… 일단 먹으면서 생각하자.","JPN":"ふう……とりあえず、食べながら考えよう。","ENG":"Phew... Let's think about it while eating.","TWN":"呼…我們邊吃邊想吧。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어라? 햄버거가 없어?! 빈 봉투잖아!","JPN":"あれ？　ハンバーガーがない！？　空っぽじゃないか！","ENG":"Huh? It's empty! Where are the burgers?!","TWN":"呃？怎麼沒有漢堡？！這是一個空袋子！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"잠깐, 또 쪽지가…?!","JPN":"待てよ、またメモが……！？","ENG":"Wait, there's another memo...?!","TWN":"等等，又是紙條…？！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FOOLSDAY_THIEF_LETTER_NULL","text":{"KOREA":"<color=#ffd34c>아하하, 제가 좋아하는 가게의 버거 맛이 궁금하셨나요?</color>","JPN":"<color=#ffd34c>あはは、私の好きなお店のバーガーの味が気になったのですか？</color>","ENG":"<color=#ffd34c>Ah hah hah! Have you wondered what the burger from my favorite restaurant would taste like?</color>","TWN":"<color=#ffd34c>哈哈哈，看來你很好奇我最喜歡的漢堡是什麼味道的呢？</color>"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L44_1","type":"dialog","speaker":"FOOLSDAY_THIEF_LETTER_NULL","text":{"KOREA":"<color=#ffd34c>제가 마침 배가 고파서 말이죠. 제인 씨와 함께 맛있게 먹어드릴게요~</color>","JPN":"<color=#ffd34c>ちょうどお腹が空いたので。ジェーンさんと一緒に美味しくいただきますね！</color>","ENG":"<color=#ffd34c>I was also hungry, so Jane and I will enjoy them to the utmost!</color>","TWN":"<color=#ffd34c>正好我現在很餓，漢堡我就收下了，我會和珍妮好好享用的~</color>"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FOOLSDAY_THIEF_LETTER_NULL","text":{"KOREA":"<color=#ffd34c>맛있는 버거를 대접해 드린 보답으로… 이번 타겟은 카린 양의 사무소로 정했답니다.</color>","JPN":"<color=#ffd34c>美味しいバーガーを頂いたお礼に……次のターゲットはカリンさんの事務所に決めました。</color>","ENG":"<color=#ffd34c>And in return for treating us out to these delicious burgers... I have decided my next target to be Karin's office.</color>","TWN":"<color=#ffd34c>作為回報…這次的目標就定為卡琳小姐的事務所了。</color>"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"조사를 시작하죠 조수. 의뢰 들어온 거 전부 캔슬해주세요!","JPN":"調査を始めましょう、助手さん。今入っている依頼は、全部キャンセルで！","ENG":"Assistant, let's begin the investigation. Cancel all other jobs that came in!","TWN":"我們開始調查吧，羅那魯多·李。請取消所有委託！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"괴도 J… 아니, JSY! 이번엔 반드시 붙잡을 겁니다!","JPN":"怪盗J……いや、怪盗ジョーカー！　今度は必ず捕まえてみせます！","ENG":"Phantom Thief J... No, JSY! I'll catch you this time!","TWN":"怪盜J…不，怪盜周時雨！這次我一定會抓住你！"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L1_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어… 그냥 경찰을 부르는 게 더 빠르지 않을까?","JPN":"えっと……警察を呼んだ方が早いんじゃないか？","ENG":"Um... wouldn't it be faster to just call the cops?","TWN":"呃…直接報警不是更快嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};